$.ajax({
  url: '/api/products',
  method: 'GET',
  data: { page: 1 },
  dataType: 'json',
})
.done(data => renderProducts(data))
.fail(jqXHR => showError(jqXHR.responseJSON?.message))
.always(() => hideLoader());

// CSRF setup
$.ajaxSetup({
  headers: {
    'X-CSRF-Token': $('meta[name="csrf-token"]').attr('content')
  }
});
